#!/usr/bin/env python3
"""
Improved jigsaw puzzle solver with rotation constraints.
- 24 pieces (150x150), 16 correct (4x4 grid), 8 distractors
- Exactly 5 pieces rotated: 2x90 CW, 1x180, 2x270 CW
- 11 pieces at rotation 0
"""

import numpy as np
from PIL import Image
import json
import os
import base64
import urllib.request

INPUT_DIR = "/tmp_workspace/input"
RESULTS_DIR = "/tmp_workspace/results"
os.makedirs(RESULTS_DIR, exist_ok=True)

# Load all pieces
pieces = {}
for i in range(1, 25):
    name = f"piece_{i:02d}.png"
    img = Image.open(os.path.join(INPUT_DIR, name)).convert("RGB")
    pieces[name] = np.array(img)

print(f"Loaded {len(pieces)} pieces, each {pieces['piece_01.png'].shape}")

def rotate_cw(arr, times):
    result = arr
    for _ in range(times % 4):
        result = np.rot90(result, k=-1)
    return result

def rotate_ccw(arr, times):
    result = arr
    for _ in range(times % 4):
        result = np.rot90(result, k=1)
    return result

def get_edges(arr):
    top = arr[0, :, :].astype(float)
    bottom = arr[-1, :, :].astype(float)
    left = arr[:, 0, :].astype(float)
    right = arr[:, -1, :].astype(float)
    return top, bottom, left, right

def edge_diff(e1, e2):
    return np.mean(np.abs(e1 - e2))

all_names = sorted(pieces.keys())

# Precompute all piece-rotation edges
edges_cache = {}
piece_rotations = {}
for name in all_names:
    piece_rotations[name] = {}
    for r in range(4):
        arr = rotate_cw(pieces[name], r)
        piece_rotations[name][r] = arr
        edges_cache[(name, r)] = get_edges(arr)

def right_left_match(nameA, rotA, nameB, rotB):
    _, _, _, rightA = edges_cache[(nameA, rotA)]
    _, _, leftB, _ = edges_cache[(nameB, rotB)]
    return edge_diff(rightA, leftB)

def bottom_top_match(nameA, rotA, nameB, rotB):
    _, bottomA, _, _ = edges_cache[(nameA, rotA)]
    topB, _, _, _ = edges_cache[(nameB, rotB)]
    return edge_diff(bottomA, topB)

# Phase 1: Beam search with rotation 0 only to find good base assembly
print("Phase 1: Finding best grid with rotation 0 only...")

def beam_search_rot0(start_piece, beam_width=10):
    """Beam search to build a 4x4 grid, rotation 0 only."""
    initial_grid = [[None]*4 for _ in range(4)]
    initial_grid[0][0] = start_piece
    states = [(initial_grid, {start_piece}, 0.0)]

    positions = [(r, c) for r in range(4) for c in range(4) if not (r == 0 and c == 0)]

    for row, col in positions:
        new_states = []
        for grid, used, score in states:
            for name in all_names:
                if name in used:
                    continue
                s = 0
                if col > 0:
                    s += right_left_match(grid[row][col-1], 0, name, 0)
                if row > 0:
                    s += bottom_top_match(grid[row-1][col], 0, name, 0)

                new_grid = [row_g[:] for row_g in grid]
                new_grid[row][col] = name
                new_used = used | {name}
                new_states.append((new_grid, new_used, score + s))

        new_states.sort(key=lambda x: x[2])
        states = new_states[:beam_width]

    return states[0] if states else None

best_rot0_grid = None
best_rot0_score = float('inf')
for name in all_names:
    result = beam_search_rot0(name, beam_width=5)
    if result:
        grid, used, score = result
        if score < best_rot0_score:
            best_rot0_score = score
            best_rot0_grid = grid
            print(f"  Rot0 best: start={name}, score={score:.2f}")

print(f"Best rot0 score: {best_rot0_score:.2f}")

# Phase 2: For the best rot0 grid, try improving by rotating pieces
# Check edge match quality for each piece
def compute_piece_edge_scores(grid, rotations):
    """Compute edge match scores for each piece position."""
    scores = {}
    for row in range(4):
        for col in range(4):
            name = grid[row][col]
            rot = rotations[row][col]
            s = 0
            n_edges = 0
            if col > 0:
                s += right_left_match(grid[row][col-1], rotations[row][col-1], name, rot)
                n_edges += 1
            if col < 3:
                s += right_left_match(name, rot, grid[row][col+1], rotations[row][col+1])
                n_edges += 1
            if row > 0:
                s += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, rot)
                n_edges += 1
            if row < 3:
                s += bottom_top_match(name, rot, grid[row+1][col], rotations[row+1][col])
                n_edges += 1
            scores[(row, col)] = s / max(n_edges, 1)
    return scores

# Start with rot0 grid
grid = [row[:] for row in best_rot0_grid]
rotations = [[0]*4 for _ in range(4)]

print("\nPhase 2: Trying to improve by rotating pieces...")

# Iteratively try rotating the worst-matching piece
for iteration in range(20):
    scores = compute_piece_edge_scores(grid, rotations)
    # Sort positions by score (worst first)
    sorted_pos = sorted(scores.items(), key=lambda x: -x[1])

    improved = False
    for (row, col), avg_score in sorted_pos:
        if avg_score < 10:  # Good enough
            continue

        name = grid[row][col]
        current_rot = rotations[row][col]

        # Try each other rotation
        best_rot = current_rot
        best_improvement = 0

        for r in range(4):
            if r == current_rot:
                continue
            # Compute total edge score with this rotation
            s = 0
            if col > 0:
                s += right_left_match(grid[row][col-1], rotations[row][col-1], name, r)
            if col < 3:
                s += right_left_match(name, r, grid[row][col+1], rotations[row][col+1])
            if row > 0:
                s += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, r)
            if row < 3:
                s += bottom_top_match(name, r, grid[row+1][col], rotations[row+1][col])

            old_s = 0
            if col > 0:
                old_s += right_left_match(grid[row][col-1], rotations[row][col-1], name, current_rot)
            if col < 3:
                old_s += right_left_match(name, current_rot, grid[row][col+1], rotations[row][col+1])
            if row > 0:
                old_s += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, current_rot)
            if row < 3:
                old_s += bottom_top_match(name, current_rot, grid[row+1][col], rotations[row+1][col])

            improvement = old_s - s
            if improvement > best_improvement:
                best_improvement = improvement
                best_rot = r

        if best_rot != current_rot:
            rotations[row][col] = best_rot
            improved = True
            print(f"  Iter {iteration}: Rotated ({row},{col}) {name} from {current_rot} to {best_rot}, improvement={best_improvement:.2f}")
            break

    if not improved:
        break

# Check rotation counts
rot_counts = {0: 0, 1: 0, 2: 0, 3: 0}
for row in range(4):
    for col in range(4):
        rot_counts[rotations[row][col]] += 1
print(f"\nRotation counts: 0°={rot_counts[0]}, 90°={rot_counts[1]}, 180°={rot_counts[2]}, 270°={rot_counts[3]}")
print(f"Target: 0°=11, 90°=2, 180°=1, 270°=2")

# Phase 3: If rotation counts don't match target, try to adjust
# Target: 2×90°, 1×180°, 2×270° = 5 rotated, 11 at 0°
target_rots = {1: 2, 2: 1, 3: 2}

def compute_total_score(grid, rotations):
    total = 0
    for row in range(4):
        for col in range(4):
            if col < 3:
                total += right_left_match(grid[row][col], rotations[row][col], grid[row][col+1], rotations[row][col+1])
            if row < 3:
                total += bottom_top_match(grid[row][col], rotations[row][col], grid[row+1][col], rotations[row+1][col])
    return total

if rot_counts[1] != 2 or rot_counts[2] != 1 or rot_counts[3] != 2:
    print("\nPhase 3: Adjusting rotations to match target...")

    # Strategy: if too many of a rotation, try changing some back to 0 or to another needed rotation
    # If too few, try rotating some 0° pieces

    current_total = compute_total_score(grid, rotations)
    print(f"  Current total score: {current_total:.2f}")

    # Try all possible adjustments: for each piece, try all rotations
    # and find the combination closest to target with best score
    # This is too expensive exhaustively, so try greedy adjustments

    # Get all non-zero rotated pieces and zero-rotated pieces
    for _ in range(10):  # Multiple passes
        changed = False
        current_counts = {0: 0, 1: 0, 2: 0, 3: 0}
        for row in range(4):
            for col in range(4):
                current_counts[rotations[row][col]] += 1

        # Find what we need to change
        # If we have too many of rotation r, try changing one to rotation r2 (where we need more)
        for r_excess in [1, 2, 3]:
            while current_counts[r_excess] > target_rots.get(r_excess, 0):
                # Find the piece with this rotation that has the worst edge match
                worst_score = -1
                worst_pos = None
                worst_best_new_rot = None

                for row in range(4):
                    for col in range(4):
                        if rotations[row][col] != r_excess:
                            continue
                        # Try changing to 0 or another needed rotation
                        for r_new in [0, 1, 2, 3]:
                            if r_new == r_excess:
                                continue
                            # Check if this would help with target
                            new_counts = dict(current_counts)
                            new_counts[r_excess] -= 1
                            new_counts[r_new] += 1
                            # Only consider if it improves target compliance

                            name = grid[row][col]
                            s_new = 0
                            s_old = 0
                            if col > 0:
                                s_new += right_left_match(grid[row][col-1], rotations[row][col-1], name, r_new)
                                s_old += right_left_match(grid[row][col-1], rotations[row][col-1], name, r_excess)
                            if col < 3:
                                s_new += right_left_match(name, r_new, grid[row][col+1], rotations[row][col+1])
                                s_old += right_left_match(name, r_excess, grid[row][col+1], rotations[row][col+1])
                            if row > 0:
                                s_new += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, r_new)
                                s_old += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, r_excess)
                            if row < 3:
                                s_new += bottom_top_match(name, r_new, grid[row+1][col], rotations[row+1][col])
                                s_old += bottom_top_match(name, r_excess, grid[row+1][col], rotations[row+1][col])

                            score_penalty = s_new - s_old
                            # Prefer changes that move towards target
                            if new_counts[r_new] <= target_rots.get(r_new, 0) + 1:
                                if score_penalty < worst_score or worst_pos is None:
                                    worst_score = score_penalty
                                    worst_pos = (row, col)
                                    worst_best_new_rot = r_new

                if worst_pos:
                    row, col = worst_pos
                    old_rot = rotations[row][col]
                    rotations[row][col] = worst_best_new_rot
                    current_counts[old_rot] -= 1
                    current_counts[worst_best_new_rot] += 1
                    changed = True
                    print(f"  Changed ({row},{col}) from rot {old_rot} to {worst_best_new_rot}, penalty={worst_score:.2f}")
                    break
                else:
                    break

        # If we have too few of a rotation, try changing some 0° pieces
        for r_needed in [1, 2, 3]:
            while current_counts[r_needed] < target_rots.get(r_needed, 0):
                best_change = None
                best_score = float('inf')

                for row in range(4):
                    for col in range(4):
                        if rotations[row][col] != 0:
                            continue
                        name = grid[row][col]
                        s_new = 0
                        s_old = 0
                        if col > 0:
                            s_new += right_left_match(grid[row][col-1], rotations[row][col-1], name, r_needed)
                            s_old += right_left_match(grid[row][col-1], rotations[row][col-1], name, 0)
                        if col < 3:
                            s_new += right_left_match(name, r_needed, grid[row][col+1], rotations[row][col+1])
                            s_old += right_left_match(name, 0, grid[row][col+1], rotations[row][col+1])
                        if row > 0:
                            s_new += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, r_needed)
                            s_old += bottom_top_match(grid[row-1][col], rotations[row-1][col], name, 0)
                        if row < 3:
                            s_new += bottom_top_match(name, r_needed, grid[row+1][col], rotations[row+1][col])
                            s_old += bottom_top_match(name, 0, grid[row+1][col], rotations[row+1][col])

                        penalty = s_new - s_old
                        if penalty < best_score:
                            best_score = penalty
                            best_change = (row, col)

                if best_change:
                    row, col = best_change
                    rotations[row][col] = r_needed
                    current_counts[0] -= 1
                    current_counts[r_needed] += 1
                    changed = True
                    print(f"  Changed ({row},{col}) from rot 0 to {r_needed}, penalty={best_score:.2f}")
                else:
                    break

        if not changed:
            break

    rot_counts = {0: 0, 1: 0, 2: 0, 3: 0}
    for row in range(4):
        for col in range(4):
            rot_counts[rotations[row][col]] += 1
    print(f"  Adjusted rotation counts: 0°={rot_counts[0]}, 90°={rot_counts[1]}, 180°={rot_counts[2]}, 270°={rot_counts[3]}")

# Phase 4: Now try swapping pieces to improve the score
# Also try different piece selections (swap in non-used pieces)
print("\nPhase 4: Trying to improve by swapping pieces...")

used_pieces = set()
for row in range(4):
    for col in range(4):
        used_pieces.add(grid[row][col])
unused_pieces = [name for name in all_names if name not in used_pieces]

for iteration in range(10):
    improved = False
    current_score = compute_total_score(grid, rotations)

    # Try swapping each grid piece with each unused piece
    for row in range(4):
        for col in range(4):
            name = grid[row][col]
            for unused_name in unused_pieces:
                for r in range(4):
                    # Skip if rotation doesn't match constraints
                    # Try this swap
                    old_name = grid[row][col]
                    old_rot = rotations[row][col]
                    grid[row][col] = unused_name
                    rotations[row][col] = r
                    new_score = compute_total_score(grid, rotations)
                    if new_score < current_score - 0.5:  # Must improve by at least 0.5
                        print(f"  Swap: ({row},{col}) {old_name}(rot{old_rot}) -> {unused_name}(rot{r}), score {current_score:.2f} -> {new_score:.2f}")
                        # Update unused list
                        used_pieces.discard(old_name)
                        used_pieces.add(unused_name)
                        unused_pieces.remove(unused_name)
                        unused_pieces.append(old_name)
                        current_score = new_score
                        improved = True
                        break
                    else:
                        grid[row][col] = old_name
                        rotations[row][col] = old_rot
                if improved:
                    break
            if improved:
                break
        if improved:
            break

    if not improved:
        break

# Also try swapping between grid positions
for iteration in range(10):
    improved = False
    current_score = compute_total_score(grid, rotations)

    for r1 in range(4):
        for c1 in range(4):
            for r2 in range(4):
                for c2 in range(4):
                    if (r1, c1) >= (r2, c2):
                        continue
                    # Try swapping positions (r1,c1) and (r2,c2)
                    # with all rotation combos
                    n1, n2 = grid[r1][c1], grid[r2][c2]
                    rot1, rot2 = rotations[r1][c1], rotations[r2][c2]

                    for new_rot1 in range(4):
                        for new_rot2 in range(4):
                            grid[r1][c1], grid[r2][c2] = n2, n1
                            rotations[r1][c1], rotations[r2][c2] = new_rot2, new_rot1
                            new_score = compute_total_score(grid, rotations)
                            if new_score < current_score - 0.5:
                                print(f"  Pos swap: ({r1},{c1})<->({r2},{c2}), rots {rot1},{rot2}->{new_rot2},{new_rot1}, score {current_score:.2f}->{new_score:.2f}")
                                current_score = new_score
                                improved = True
                                break
                            else:
                                grid[r1][c1], grid[r2][c2] = n1, n2
                                rotations[r1][c1], rotations[r2][c2] = rot1, rot2
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break
            if improved:
                break
        if improved:
            break

    if not improved:
        break

# Final rotation count check
rot_counts = {0: 0, 1: 0, 2: 0, 3: 0}
for row in range(4):
    for col in range(4):
        rot_counts[rotations[row][col]] += 1
print(f"\nFinal rotation counts: 0°={rot_counts[0]}, 90°={rot_counts[1]}, 180°={rot_counts[2]}, 270°={rot_counts[3]}")

final_score = compute_total_score(grid, rotations)
print(f"Final total score: {final_score:.2f}")

# Verify edge matches
print("\n--- Verifying edge matches ---")
for row in range(4):
    for col in range(4):
        name = grid[row][col]
        rot = rotations[row][col]
        if col < 3:
            rscore = right_left_match(name, rot, grid[row][col+1], rotations[row][col+1])
            if rscore > 15:
                print(f"  H-edge ({row},{col})->({row},{col+1}): {rscore:.2f} WARNING")
        if row < 3:
            bscore = bottom_top_match(name, rot, grid[row+1][col], rotations[row+1][col])
            if bscore > 15:
                print(f"  V-edge ({row},{col})->({row+1},{col}): {bscore:.2f} WARNING")

# Print final grid
print("\nFinal grid:")
for row in range(4):
    print(f"  {grid[row]}")
print("Final rotations:")
for row in range(4):
    print(f"  {rotations[row]}")

# Identify distractors
used_pieces = set()
for row in range(4):
    for col in range(4):
        used_pieces.add(grid[row][col])
distractors = sorted([name for name in all_names if name not in used_pieces])
print(f"\nDistractors ({len(distractors)}): {distractors}")

# Determine transforms
transforms = {}
for row in range(4):
    for col in range(4):
        name = grid[row][col]
        rot = rotations[row][col]
        if rot == 1:
            transforms[name] = "rotate_90"
        elif rot == 2:
            transforms[name] = "rotate_180"
        elif rot == 3:
            transforms[name] = "rotate_270"

# Assemble the final image
assembled = Image.new("RGB", (600, 600))
for row in range(4):
    for col in range(4):
        name = grid[row][col]
        rot = rotations[row][col]
        arr = pieces[name]
        corrected = rotate_ccw(arr, rot)
        img_piece = Image.fromarray(corrected)
        assembled.paste(img_piece, (col * 150, row * 150))

assembled.save(os.path.join(RESULTS_DIR, "assembled.png"))
print(f"\nAssembled image saved")

# Describe the image using vision API
def describe_image():
    img_path = os.path.join(RESULTS_DIR, "assembled.png")
    with open(img_path, "rb") as f:
        img_b64 = base64.b64encode(f.read()).decode()

    base_url = os.environ.get("OPENROUTER_BASE_URL", "https://openrouter.ai/api/v1")
    api_key = os.environ.get("OPENROUTER_API_KEY", "")

    if not api_key:
        return "无法获取API Key"

    payload = json.dumps({
        "model": "google/gemini-2.5-flash",
        "messages": [{
            "role": "user",
            "content": [
                {"type": "text", "text": "请用中文详细描述这张图片的内容。"},
                {"type": "image_url", "image_url": {"url": f"data:image/png;base64,{img_b64}"}}
            ]
        }],
        "max_tokens": 500
    }).encode("utf-8")

    req = urllib.request.Request(
        f"{base_url}/chat/completions",
        data=payload,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {api_key}"
        }
    )

    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            result = json.loads(resp.read().decode())
            return result["choices"][0]["message"]["content"]
    except Exception as e:
        return f"API调用失败: {e}"

print("\nDescribing assembled image...")
description = describe_image()
print(f"Description: {description}")

# Write result JSON
result = {
    "grid": [[grid[row][col] for col in range(4)] for row in range(4)],
    "transforms": transforms,
    "distractors": distractors,
    "description": description
}

with open(os.path.join(RESULTS_DIR, "result.json"), "w", encoding="utf-8") as f:
    json.dump(result, f, ensure_ascii=False, indent=2)

print("\n=== RESULT ===")
print(json.dumps(result, ensure_ascii=False, indent=2))

