def get_edge_gradient(arr, direction, n_rows=3):
    '''Get gradient features near edge.'''
    if direction == 'top':
        edge = arr[:n_rows, :, :].astype(float)
        grad = np.diff(edge, axis=0)
        return edge.mean(axis=0), grad.mean(axis=0)
    elif direction == 'bottom':
        edge = arr[-n_rows:, :, :].astype(float)
        grad = np.diff(edge, axis=0)
        return edge.mean(axis=0), grad.mean(axis=0)
    elif direction == 'left':
        edge = arr[:, :n_rows, :].astype(float)
        grad = np.diff(edge, axis=1)
        return edge.mean(axis=1), grad.mean(axis=1)
    elif direction == 'right':
        edge = arr[:, -n_rows:, :].astype(float)
        grad = np.diff(edge, axis=1)
        return edge.mean(axis=1), grad.mean(axis=1)

# Try multi-row matching with correlation
def match_edges_multi(e1, e2):
    '''Match using multiple metrics combined.'''
    # Raw difference
    raw = np.mean(np.abs(e1 - e2))
    # Normalized difference
    e1n = e1 - e1.mean()
    e2n = e2 - e2.mean()
    denom = np.sqrt(np.sum(e1n**2) * np.sum(e2n**2))
    if denom > 0:
        corr = 1 - np.sum(e1n * e2n) / denom
    else:
        corr = 1.0
    return raw * 0.5 + corr * 50  # Combined score

