#!/usr/bin/env python3
"""
Jigsaw solver v4: Using NCC (normalized cross-correlation) for edge matching.
NCC is more robust to compression artifacts and brightness differences.
"""

import numpy as np
from PIL import Image
import json
import os
import base64
import urllib.request
from collections import defaultdict

INPUT_DIR = "/tmp_workspace/input"
RESULTS_DIR = "/tmp_workspace/results"
os.makedirs(RESULTS_DIR, exist_ok=True)

pieces = {}
for i in range(1, 25):
    name = f"piece_{i:02d}.png"
    img = Image.open(os.path.join(INPUT_DIR, name)).convert("RGB")
    pieces[name] = np.array(img)

all_names = sorted(pieces.keys())

def rotate_cw(arr, times):
    result = arr
    for _ in range(times % 4):
        result = np.rot90(result, k=-1)
    return result

def rotate_ccw(arr, times):
    result = arr
    for _ in range(times % 4):
        result = np.rot90(result, k=1)
    return result

# Precompute all piece-rotation versions and their edges
# rot 0 = original, 1 = 90 CW, 2 = 180, 3 = 270 CW
edge_cache = {}
for name in all_names:
    for r in range(4):
        arr = rotate_cw(pieces[name], r)
        top = arr[0, :, :].astype(np.float64)
        bottom = arr[-1, :, :].astype(np.float64)
        left = arr[:, 0, :].astype(np.float64)
        right = arr[:, -1, :].astype(np.float64)
        edge_cache[(name, r)] = (top, bottom, left, right)

def ncc_score(e1, e2):
    """Normalized cross-correlation. Returns 1 - NCC so lower = better match."""
    e1f = e1.flatten()
    e2f = e2.flatten()
    e1n = e1f - e1f.mean()
    e2n = e2f - e2f.mean()
    denom = np.sqrt(np.sum(e1n**2) * np.sum(e2n**2))
    if denom < 1e-10:
        return 1.0  # No signal
    ncc = np.sum(e1n * e2n) / denom
    return 1.0 - ncc  # Lower = better

def mad_score(e1, e2):
    """Mean absolute difference."""
    return float(np.mean(np.abs(e1 - e2)))

# Use combined score: NCC + small weight of MAD
def combined_score(e1, e2):
    ncc = ncc_score(e1, e2)
    mad = mad_score(e1, e2)
    return ncc * 10 + mad * 0.1  # NCC dominates, MAD breaks ties

def rl_score(nA, rA, nB, rB, metric='ncc'):
    """Right-left match: A's right edge vs B's left edge."""
    _, _, _, rightA = edge_cache[(nA, rA)]
    _, _, leftB, _ = edge_cache[(nB, rB)]
    if metric == 'ncc':
        return ncc_score(rightA, leftB)
    elif metric == 'mad':
        return mad_score(rightA, leftB)
    else:
        return combined_score(rightA, leftB)

def bt_score(nA, rA, nB, rB, metric='ncc'):
    """Bottom-top match: A's bottom edge vs B's top edge."""
    _, bottomA, _, _ = edge_cache[(nA, rA)]
    topB, _, _, _ = edge_cache[(nB, rB)]
    if metric == 'ncc':
        return ncc_score(bottomA, topB)
    elif metric == 'mad':
        return mad_score(bottomA, topB)
    else:
        return combined_score(bottomA, topB)

# Compute all pairwise NCC scores
print("Computing all pairwise NCC scores...")

all_rl = []
all_bt = []

for nA in all_names:
    for rA in range(4):
        for nB in all_names:
            if nB == nA:
                continue
            for rB in range(4):
                s = rl_score(nA, rA, nB, rB, 'ncc')
                all_rl.append((s, nA, rA, nB, rB))
                s2 = bt_score(nA, rA, nB, rB, 'ncc')
                all_bt.append((s2, nA, rA, nB, rB))

all_rl.sort()
all_bt.sort()

print(f"\nBest right matches (NCC, top 30):")
for s, nA, rA, nB, rB in all_rl[:30]:
    print(f"  {nA}(r{rA}) ->R-> {nB}(r{rB}): {s:.6f} (NCC={1-s:.6f})")

print(f"\nBest bottom matches (NCC, top 30):")
for s, nA, rA, nB, rB in all_bt[:30]:
    print(f"  {nA}(r{rA}) ->D-> {nB}(r{rB}): {s:.6f} (NCC={1-s:.6f})")

# Find mutual best matches
print("\n\n=== Mutual best matches ===")
# For each (nA, rA), find best right match (nB, rB)
best_right = {}
for s, nA, rA, nB, rB in all_rl:
    if (nA, rA) not in best_right:
        best_right[(nA, rA)] = (s, nB, rB)

# For each (nB, rB), find best left match (nA, rA) - i.e., who has nB as best right match
best_left = {}
for s, nA, rA, nB, rB in all_rl:
    if (nB, rB) not in best_left or s < best_left[(nB, rB)][0]:
        best_left[(nB, rB)] = (s, nA, rA)

# For each (nA, rA), find best bottom match (nB, rB)
best_bottom = {}
for s, nA, rA, nB, rB in all_bt:
    if (nA, rA) not in best_bottom:
        best_bottom[(nA, rA)] = (s, nB, rB)

# For each (nB, rB), find best top match (nA, rA)
best_top = {}
for s, nA, rA, nB, rB in all_bt:
    if (nB, rB) not in best_top or s < best_top[(nB, rB)][0]:
        best_top[(nB, rB)] = (s, nA, rA)

print("\nMutual best right-left matches:")
mutual_rl = []
for (nA, rA), (s_rl, nB, rB) in best_right.items():
    if (nB, rB) in best_left:
        s_lr, nA2, rA2 = best_left[(nB, rB)]
        if nA2 == nA and rA2 == rA:
            mutual_rl.append((s_rl, nA, rA, nB, rB))
            print(f"  {nA}(r{rA}) ->R-> {nB}(r{rB}): {s_rl:.6f} (NCC={1-s_rl:.6f})")

print("\nMutual best bottom-top matches:")
mutual_bt = []
for (nA, rA), (s_bt, nB, rB) in best_bottom.items():
    if (nB, rB) in best_top:
        s_tb, nA2, rA2 = best_top[(nB, rB)]
        if nA2 == nA and rA2 == rA:
            mutual_bt.append((s_bt, nA, rA, nB, rB))
            print(f"  {nA}(r{rA}) ->D-> {nB}(r{rB}): {s_bt:.6f} (NCC={1-s_bt:.6f})")

# Now build the grid from mutual best matches
# Start from each possible top-left corner and build the grid
print("\n\n=== Building grid from mutual matches ===")

def build_grid_from_matches():
    """Try to build a 4x4 grid using mutual best matches."""
    # Build adjacency maps from mutual matches
    right_map = {}  # (name, rot) -> (name, rot, score) for right neighbor
    left_map = {}
    bottom_map = {}
    top_map = {}

    for s, nA, rA, nB, rB in mutual_rl:
        right_map[(nA, rA)] = (nB, rB, s)
        left_map[(nB, rB)] = (nA, rA, s)

    for s, nA, rA, nB, rB in mutual_bt:
        bottom_map[(nA, rA)] = (nB, rB, s)
        top_map[(nB, rB)] = (nA, rA, s)

    # Find top-left corner: has right and bottom matches but no left or top match
    candidates = []
    for (name, rot), (nB, rB, s_r) in right_map.items():
        if (name, rot) in bottom_map:
            nD, rD, s_d = bottom_map[(name, rot)]
            if (name, rot) not in left_map and (name, rot) not in top_map:
                candidates.append((name, rot, s_r + s_d))

    candidates.sort(key=lambda x: x[2])
    print(f"Top-left candidates: {len(candidates)}")
    for name, rot, score in candidates:
        print(f"  {name}(r{rot}): combined score={score:.6f}")

    # Try each candidate
    best_grid = None
    best_rots = None
    best_score = float('inf')

    for tl_name, tl_rot, _ in candidates:
        grid = [[None]*4 for _ in range(4)]
        rots = [[0]*4 for _ in range(4)]
        grid[0][0] = tl_name
        rots[0][0] = tl_rot
        used = {(tl_name, tl_rot)}
        used_names = {tl_name}
        total_score = 0
        valid = True

        for row in range(4):
            for col in range(4):
                if row == 0 and col == 0:
                    continue

                # Determine expected piece from mutual matches
                expected = None
                if col > 0 and (grid[row][col-1], rots[row][col-1]) in right_map:
                    rn, rr, rs = right_map[(grid[row][col-1], rots[row][col-1])]
                    expected = (rn, rr, rs, 'right')

                if row > 0 and (grid[row-1][col], rots[row-1][col]) in bottom_map:
                    bn, br, bs = bottom_map[(grid[row-1][col], rots[row-1][col])]
                    if expected is None:
                        expected = (bn, br, bs, 'bottom')
                    elif expected[0] == bn and expected[1] == br:
                        expected = (bn, br, bs + expected[2], 'both')
                    else:
                        # Conflict: right match != bottom match
                        valid = False
                        break

                if expected is None:
                    valid = False
                    break

                name, rot, score, source = expected
                if name in used_names:
                    valid = False
                    break

                grid[row][col] = name
                rots[row][col] = rot
                used_names.add(name)
                total_score += score

            if not valid:
                break

        if valid and len(used_names) == 16:
            print(f"\nValid grid from {tl_name}(r{tl_rot}): score={total_score:.6f}")
            for row in range(4):
                print(f"  {grid[row]}")
            print("  Rotations:")
            for row in range(4):
                print(f"  {rots[row]}")

            # Count rotations
            rot_count = {0:0, 1:0, 2:0, 3:0}
            for r in range(4):
                for c in range(4):
                    rot_count[rots[r][c]] += 1
            print(f"  Rot counts: 0={rot_count[0]}, 90={rot_count[1]}, 180={rot_count[2]}, 270={rot_count[3]}")

            if total_score < best_score:
                best_score = total_score
                best_grid = grid
                best_rots = rots

    return best_grid, best_rots, best_score

best_grid, best_rots, best_score = build_grid_from_matches()

if best_grid is None:
    print("\nNo valid grid from mutual matches. Trying with relaxed matching...")

    # Use top-K matches instead of just best match
    # For each (name, rot), get top 3 right and bottom matches
    top_right = defaultdict(list)
    top_bottom = defaultdict(list)

    for s, nA, rA, nB, rB in all_rl:
        if len(top_right[(nA, rA)]) < 5:
            top_right[(nA, rA)].append((s, nB, rB))

    for s, nA, rA, nB, rB in all_bt:
        if len(top_bottom[(nA, rA)]) < 5:
            top_bottom[(nA, rA)].append((s, nB, rB))

    # Try all combinations with beam search
    def beam_search_ncc(start_name, start_rot, beam_width=30):
        grid = [[None]*4 for _ in range(4)]
        grid[0][0] = start_name
        rots = [[0]*4 for _ in range(4)]
        rots[0][0] = start_rot
        states = [(grid, rots, {start_name}, 0.0)]

        positions = [(r, c) for r in range(4) for c in range(4) if not (r == 0 and c == 0)]

        for row, col in positions:
            new_states = []
            for grid, rots, used, score in states:
                for name in all_names:
                    if name in used:
                        continue
                    for r in range(4):
                        s = 0
                        if col > 0:
                            s += rl_score(grid[row][col-1], rots[row][col-1], name, r)
                        if row > 0:
                            s += bt_score(grid[row-1][col], rots[row-1][col], name, r)

                        new_grid = [rg[:] for rg in grid]
                        new_rots = [rr[:] for rr in rots]
                        new_grid[row][col] = name
                        new_rots[row][col] = r
                        new_states.append((new_grid, new_rots, used | {name}, score + s))

            new_states.sort(key=lambda x: x[3])
            states = new_states[:beam_width]

        return states[0] if states else None

    print("Running beam search with NCC metric...")
    best_score = float('inf')
    for name in all_names:
        for rot in range(4):
            result = beam_search_ncc(name, rot, beam_width=20)
